# Consistent Hashing with Virtual Nodes
import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, vnodes=150):
        self.vnodes = vnodes
        self.ring = {}       # hash -> physical node
        self.sorted_keys = []

    def _hash(self, key):
        return int(hashlib.md5(str(key).encode()).hexdigest(), 16)

    def add_node(self, node_id, weight=1):
        for i in range(self.vnodes * weight):
            vkey = self._hash(f"{node_id}:{i}")
            self.ring[vkey] = node_id
            bisect.insort(self.sorted_keys, vkey)

    def remove_node(self, node_id):
        for i in range(self.vnodes * 10):  # max possible weight
            vkey = self._hash(f"{node_id}:{i}")
            if vkey in self.ring:
                del self.ring[vkey]
                self.sorted_keys.remove(vkey)

    def get_node(self, key):
        if not self.ring:
            return None
        h = self._hash(key)
        idx = bisect.bisect_right(self.sorted_keys, h)
        if idx == len(self.sorted_keys):
            idx = 0
        return self.ring[self.sorted_keys[idx]]

# ABAP equivalent: READ TABLE with binary search on SORTED TABLE
# LOOP AT sorted_keys INTO DATA(vkey) WHERE vkey >= hash.
#   node = ring[vkey]; EXIT.
# ENDLOOP.

