# Weighted Round Robin load balancing
import itertools

class WeightedRoundRobin:
    def __init__(self, servers_with_weights):
        self.servers = []
        for server, weight in servers_with_weights:
            self.servers.extend([server] * weight)
        self.it = itertools.cycle(self.servers)

    def next_server(self):
        return next(self.it)

# Least Connections with health checks
class LeastConnections:
    def __init__(self, servers):
        self.connections = {s: 0 for s in servers}
        self.healthy = {s: True for s in servers}

    def acquire(self, server):
        self.connections[server] += 1

    def release(self, server):
        self.connections[server] = max(0, self.connections[server] - 1)

    def next_server(self):
        healthy_servers = [s for s, h in self.healthy.items() if h]
        return min(healthy_servers, key=lambda s: self.connections[s])

# Circuit Breaker pattern
class CircuitBreaker:
    def __init__(self, failure_threshold=5, recovery_timeout=30):
        self.state = "CLOSED"
        self.failure_count = 0
        self.threshold = failure_threshold
        self.timeout = recovery_timeout

    def record_failure(self):
        self.failure_count += 1
        if self.failure_count >= self.threshold:
            self.state = "OPEN"

    def record_success(self):
        self.failure_count = 0
        self.state = "CLOSED"

    def attempt_request(self):
        if self.state == "OPEN":
            return False  # circuit is open, fail fast
        return True

