    event_type: str
    aggregate_id: str
    data: dict
    version: int

# Command side: validate + persist events
def handle_create_order(cmd):
    event = Event("OrderCreated", cmd.id, {"items": cmd.items}, 1)
    event_store.append(event)
    return event

# Query side: build projection from events
def build_projection(order_id):
    events = event_store.get_events(order_id)
    state = {"status": None, "items": []}
    for ev in sorted(events, key=lambda e: e.version):
        if ev.event_type == "OrderCreated":
            state.update({"status": "created", "items": ev.data["items"]})
        elif ev.event_type == "OrderShipped":
            state["status"] = "shipped"
    return state

