# SWIM-style gossip membership with φ-accrual
import random
import time
import math

class GossipNode:
    def __init__(self, node_id, peers):
        self.id = node_id
        self.peers = peers
        self.members = {p: {"status": "alive", "incarnation": 0, "last_heard": time.time()} for p in peers}
        self.members[node_id] = {"status": "alive", "incarnation": 0, "last_heard": time.time()}
        self.phi_threshold = 8.0

    def gossip_round(self):
        targets = random.sample(
            [p for p in self.peers if p != self.id],
            k=min(3, len(self.peers) - 1)
        )
        for target in targets:
            updates = [(n, m["status"], m["incarnation"]) for n, m in self.members.items()]
            self._merge(target, updates)

    def _merge(self, peer, updates):
        for node_id, status, inc in updates:
            cur = self.members.get(node_id, {})
            if not cur or inc > cur.get("incarnation", 0):
                self.members[node_id] = {"status": status, "incarnation": inc, "last_heard": time.time()}

    def compute_phi(self, node_id, now):
        elapsed = now - self.members[node_id]["last_heard"]
        # Simplified φ: -log10(P(no heartbeat given elapsed))
        mean = 1.0  # expected heartbeat interval
        if elapsed <= mean:
            return 0.01
        return min(20.0, -math.log10(math.exp(-(elapsed - mean) / mean)))

# ABAP: SAP message server = centralized heartbeat (SM51)
# Gossip = decentralized, no SPOF, O(log N) convergence

