# Vector Clock: causality tracking
from dataclasses import dataclass

@dataclass
class VectorClock:
    clocks: dict  # node_id -> counter

    def increment(self, node_id):
        self.clocks[node_id] = self.clocks.get(node_id, 0) + 1

    def merge(self, other):
        merged = dict(self.clocks)
        for node_id, counter in other.clocks.items():
            merged[node_id] = max(merged.get(node_id, 0), counter)
        return VectorClock(merged)

    def __le__(self, other):
        for node_id, counter in self.clocks.items():
            if counter > other.clocks.get(node_id, 0):
                return False
        return True

    def concurrent(self, other):
        return not (self <= other or other <= self)

# CRDT: G-Counter (grow-only counter)
class GCounter:
    def __init__(self, node_id, n_nodes):
        self.node_id = node_id
        self.counts = [0] * n_nodes

    def increment(self):
        self.counts[self.node_id] += 1

    def value(self):
        return sum(self.counts)

    def merge(self, other):
        for i in range(len(self.counts)):
            self.counts[i] = max(self.counts[i], other.counts[i])

# PN-Counter: uses two G-Counters (pos + neg)
class PNCounter:
    def __init__(self, node_id, n_nodes):
        self.pos = GCounter(node_id, n_nodes)
        self.neg = GCounter(node_id, n_nodes)

    def add(self, v):
        if v > 0: self.pos.increment()
        elif v < 0: self.neg.increment()

    def value(self):
        return self.pos.value() - self.neg.value()

    def merge(self, other):
        self.pos.merge(other.pos)
        self.neg.merge(other.neg)

# ABAP: ALE change pointers = manual vector clock
# IDoc status = causal history
# CRDTs automate what SAP does manually via WE02/WE05

